import{_ as e}from"./chunks/quickstart_01.CAs9iatn.js";import{_ as a,o as r,c as s,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"شروع سریع","description":"","frontmatter":{},"headers":[],"relativePath":"fa/getting-started/quickstart.md","filePath":"fa/getting-started/quickstart.md"}'),o={name:"fa/getting-started/quickstart.md"};function c(n,t,l,d,p,g){return r(),s("div",null,[...t[0]||(t[0]=[i('<h1 id="شروع-سریع" tabindex="-1"><i class="ph ph-target"></i> شروع سریع <a class="header-anchor" href="#شروع-سریع" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-target&quot;&gt;&lt;/i&gt; شروع سریع&quot;">​</a></h1><p>افزونه WebAP با رویکرد <em>Plug-and-Play</em> طراحی شده است. نیازی به نوشتن کد یا اضافه کردن مدیران (Managers) به صحنه اولیه خود ندارید — سیستم به‌طور خودکار آماده‌سازی می‌شود.</p><h2 id="۱-فعال‌سازی-افزونه" tabindex="-1">۱. فعال‌سازی افزونه <a class="header-anchor" href="#۱-فعال‌سازی-افزونه" aria-label="Permalink to &quot;۱. فعال‌سازی افزونه&quot;">​</a></h2><p>۱. به مسیر <strong>Edit -&gt; Project Settings -&gt; Adaptive Performance (Web)</strong> بروید.<br> ۲. گزینه <strong>Enable Web Adaptive Performance</strong> را فعال کنید.<br> ۳. تب Scalers را باز کرده و ماژول‌های اضافی را که با ویژگی‌های بازی شما (مانند مرحله فیزیک یا کیفیت سایه) هماهنگ‌تر هستند، فعال کنید (برای جزئیات بیشتر به <a href="./../scalers/reference">مرجع Scalerها</a> مراجعه کنید).</p><p><img src="'+e+'" alt=""></p><div class="info custom-block"><p class="custom-block-title">تنظیمات پیش‌فرض</p><p>تنظیمات پیش‌فرض به‌گونه‌ای پیکربندی شده‌اند که عملکردی بهینه برای اکثر پروژه‌ها ارائه دهند. آنها را تغییر ندهید.</p></div><h2 id="۲-پیکربندی-player-settings" tabindex="-1">۲. پیکربندی Player Settings <a class="header-anchor" href="#۲-پیکربندی-player-settings" aria-label="Permalink to &quot;۲. پیکربندی Player Settings&quot;">​</a></h2><p>برای اینکه Tracker افزونه بتواند به‌صورت ریاضی بین تأخیرهای پردازنده (CPU) و کارت گرافیک (GPU) تفاوت قائل شود، به دسترسی به زمان‌بندی دقیق فریم‌های سخت‌افزار نیاز دارد.</p><div class="warning custom-block"><p class="custom-block-title">آمارهای زمان‌بندی فریم (Frame Timing Stats)</p><p>به مسیر <strong>Edit -&gt; Project Settings -&gt; Player -&gt; Other Settings -&gt; Rendering</strong> بروید و تیک <strong>Frame Timing Stats</strong> را بزنید. بدون این تنظیم، تشخیص گلوگاه (Bottleneck) عمل نخواهد کرد.</p></div><h2 id="۳-پیکربندی-گرافیک" tabindex="-1">۳. پیکربندی گرافیک <a class="header-anchor" href="#۳-پیکربندی-گرافیک" aria-label="Permalink to &quot;۳. پیکربندی گرافیک&quot;">​</a></h2><p>از ایجاد تنظیمات پیش‌فرض کیفیت مجزا (Low, Medium, High) برای دستگاه‌های مختلف که بازیکن را مجبور به انتخاب دستی آنها می‌کند، دست بردارید.</p><div class="tip custom-block"><p class="custom-block-title">کیفیت گرافیک را به حداکثر برسانید</p><p>پروژه خود را برای حداکثر کیفیت پیکربندی کنید. برای BiRP، این کار را در <code>Project Settings -&gt; Quality</code> و برای URP، درون <code>URP Asset</code> خود انجام دهید. اگر دستگاه بازیکن فاقد Performance Headroom (حاشیه عملکرد) باشد، افزونه به‌طور خودکار و روان بار را در طول اجرای بازی کاهش می‌دهد و فقط از Scalerهایی که فعال کرده‌اید استفاده می‌کند.</p></div>',12)])])}const P=a(o,[["render",c]]);export{u as __pageData,P as default};
